import React, { useState } from 'react';
import { Icon } from '@capital/component';
import { showToasts } from '@capital/common';
import { Song } from '../../const';
import { usePlayerStore } from '../../store/playerStore';
import { isFavorite, toggleFavorite } from '../../utils/storage';
import { buildSongCardContent } from '../../utils/share';
import { AddToPlaylistMenu } from './AddToPlaylistMenu';

async function copyShare(text: string, label: string) {
  try {
    await navigator.clipboard.writeText(text);
    showToasts(`${label}已复制，可粘贴到任意聊天窗口发送`, 'success');
  } catch {
    showToasts('复制失败，请检查浏览器权限', 'error');
  }
}

export const SongRow: React.FC<{ song: Song; queue: Song[]; index: number }> = ({
  song,
  queue,
  index,
}) => {
  const playSong = usePlayerStore((s) => s.playSong);
  const currentSong = usePlayerStore((s) => s.currentSong);
  const [fav, setFav] = useState(() => isFavorite(song));
  const active = currentSong?.id === song.id && currentSong?.source === song.source;

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 8,
        padding: '8px 6px',
        borderRadius: 8,
        background: active ? 'rgba(34,197,94,0.12)' : 'transparent',
      }}
    >
      <span style={{ width: 20, fontSize: 12, opacity: 0.5, textAlign: 'center' }}>{index + 1}</span>
      <div style={{ flex: 1, minWidth: 0, cursor: 'pointer' }} onClick={() => playSong(song, queue)}>
        <div style={{ fontSize: 13, fontWeight: active ? 700 : 400, color: active ? '#22c55e' : 'inherit', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
          {song.name}
        </div>
        <div style={{ fontSize: 11, opacity: 0.55, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
          {song.artist} {song.album ? `· ${song.album}` : ''}
        </div>
      </div>

      <div
        style={{ cursor: 'pointer', display: 'flex' }}
        title={fav ? '取消收藏' : '收藏'}
        onClick={() => setFav(toggleFavorite(song))}
      >
        <Icon icon={fav ? 'mdi:heart' : 'mdi:heart-outline'} width={16} color={fav ? '#f43f5e' : undefined} />
      </div>

      <AddToPlaylistMenu song={song} />

      <div
        style={{ cursor: 'pointer', display: 'flex' }}
        title="复制歌曲分享卡片"
        onClick={() => copyShare(buildSongCardContent(song), '歌曲')}
      >
        <Icon icon="mdi:share-variant" width={16} />
      </div>
    </div>
  );
};
