import React, { useState } from 'react';
import { Icon } from '@capital/component';
import { showErrorToasts } from '@capital/common';
import { MUSIC_SOURCES, MusicSource, Song } from '../../const';
import { searchMusic } from '../../api/musicApi';
import { useSettingsStore } from '../../store/settingsStore';
import { usePlayerStore } from '../../store/playerStore';
import { SongRow } from './SongRow';
import { Translate } from '../../translate';

export const Search: React.FC = () => {
  const defaultSource = useSettingsStore((s) => s.settings.defaultSource);
  const [source, setSource] = useState<MusicSource>(defaultSource);
  const [keyword, setKeyword] = useState('');
  const [results, setResults] = useState<Song[]>([]);
  const [loading, setLoading] = useState(false);
  const playSong = usePlayerStore((s) => s.playSong);

  const doSearch = async () => {
    if (!keyword.trim()) return;
    setLoading(true);
    try {
      const songs = await searchMusic(keyword.trim(), source, 30);
      setResults(songs);
    } catch (e) {
      showErrorToasts(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <div style={{ display: 'flex', gap: 8, padding: '10px 12px' }}>
        <select
          value={source}
          onChange={(e) => setSource(e.target.value as MusicSource)}
          style={{ padding: '6px 8px', borderRadius: 6, border: '1px solid rgba(120,120,120,0.3)', background: 'transparent', color: 'inherit' }}
        >
          {MUSIC_SOURCES.map((s) => (
            <option key={s.value} value={s.value}>
              {s.label}
            </option>
          ))}
        </select>
        <input
          value={keyword}
          onChange={(e) => setKeyword(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && doSearch()}
          placeholder={Translate.searchPlaceholder}
          style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid rgba(120,120,120,0.3)', background: 'transparent', color: 'inherit' }}
        />
        <div
          onClick={doSearch}
          style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 12px', borderRadius: 6, background: '#22c55e', color: '#fff', cursor: 'pointer' }}
        >
          <Icon icon="mdi:magnify" width={18} />
        </div>
      </div>

      <div style={{ flex: 1, overflowY: 'auto', padding: '0 12px 12px' }}>
        {loading && <div style={{ textAlign: 'center', opacity: 0.6, marginTop: 30 }}>搜索中...</div>}
        {!loading && results.length === 0 && (
          <div style={{ textAlign: 'center', opacity: 0.4, marginTop: 30 }}>输入关键字搜索歌曲 / 歌手 / 专辑</div>
        )}
        {!loading && results.length > 0 && (
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 4 }}>
            <div
              style={{ fontSize: 12, cursor: 'pointer', opacity: 0.7, display: 'flex', alignItems: 'center', gap: 4 }}
              onClick={() => results[0] && playSong(results[0], results)}
            >
              <Icon icon="mdi:play" width={14} /> 播放全部
            </div>
          </div>
        )}
        {results.map((song, i) => (
          <SongRow key={`${song.source}-${song.id}-${i}`} song={song} queue={results} index={i} />
        ))}
      </div>
    </div>
  );
};
